#!/usr/bin/env bash
# Start the dev server and run a smoke test.
# Generated by the initializer agent — edit to match your project.
set -e

# This project has no dev server — it is pure Markdown/JSON.
# Smoke test verifies the target file structure is intact.

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"

MISSING=0
for f in \
  plugins/harness/commands/init.md \
  plugins/harness/commands/session.md \
  plugins/harness/commands/run.md \
  plugins/harness/commands/reset.md \
  plugins/harness/commands/release.md \
  plugins/harness/agents/releaser.md \
  plugins/harness/agents/coordinator.md \
  plugins/harness/skills/harness/roles/releaser.md \
  plugins/harness/skills/harness/references/patterns.md \
  plugins/harness/skills/harness/SKILL.md \
  plugins/harness/skills/harness-sdlc/SKILL.md \
  plugins/harness/skills/harness-ea/SKILL.md
do
  if [ ! -f "$PROJECT_ROOT/$f" ]; then
    echo "MISSING: $f"
    MISSING=$((MISSING + 1))
  fi
done

if [ "$MISSING" -eq 0 ]; then
  echo "OK — all 12 target files present"
else
  echo "FAIL — $MISSING target file(s) missing"
  exit 1
fi
